// Runtime shared by every C# parser generated by parsuna.
//
// A generated grammar namespace supplies token/rule-kind enums (backed by
// `short` / `ushort`), a DfaConfig, a skip predicate, and a Drive
// callback. This library provides everything else.

using System;
using System.Collections;
using System.Collections.Generic;
using System.IO;
using System.Text;

namespace Parsuna.Runtime;

/// <summary>Source position: byte offset plus 1-based line/column.</summary>
public readonly record struct Pos(int Offset, int Line, int Column);

/// <summary>Half-open span <c>[Start, End)</c> over the source.</summary>
public readonly record struct Span(Pos Start, Pos End)
{
    public static Span Point(Pos p) => new(p, p);
}

/// <summary>A lexed token: kind id, source span, and the matched text.</summary>
public sealed record Token(short Kind, Span Span, string Text);

/// <summary>A recoverable parse or lex error with its source span.</summary>
public sealed record ParseError(string Message, Span Span)
{
    public override string ToString()
    {
        var (s, e) = (Span.Start, Span.End);
        var loc = s == e ? $"{s.Line}:{s.Column}" : $"{s.Line}:{s.Column}-{e.Line}:{e.Column}";
        return $"error[{loc}]: {Message}";
    }
}

/// <summary>
/// A single pull-parser event. Pattern-match on the concrete subtype to
/// extract its payload:
/// <code>
///   switch (ev) {
///       case EnterEvent e: ...; break;
///       case ExitEvent e:  ...; break;
///       case TokenEvent t: ...; break;
///       case ErrorEvent x: ...; break;
///   }
/// </code>
/// </summary>
public abstract record Event;

/// <summary>Opens the subtree of the given rule; <c>Pos</c> is the start of the first child.</summary>
public sealed record EnterEvent(int Rule, Pos Pos) : Event;

/// <summary>Closes the subtree of the given rule; <c>Pos</c> is the end of the last child.</summary>
public sealed record ExitEvent(int Rule, Pos Pos) : Event;

/// <summary>A token consumed from the input, including skip tokens.</summary>
public sealed record TokenEvent(Token Token) : Event;

/// <summary>A recoverable parse or lex error.</summary>
public sealed record ErrorEvent(ParseError Error) : Event;

/// <summary>Packed lexer DFA. State 0 is the dead sink; real states start at 1.</summary>
public sealed class DfaConfig
{
    public uint Start { get; }
    /// <summary>Flat table: <c>Trans[state * 256 + byte]</c> is the next state (0 = dead).</summary>
    public uint[] Trans { get; }
    /// <summary>Acceptance table: <c>Accept[state]</c> is the token-kind id (0 = non-accepting).</summary>
    public ushort[] Accept { get; }
    public DfaConfig(uint start, uint[] trans, ushort[] accept)
    {
        Start = start;
        Trans = trans;
        Accept = accept;
    }
}

/// <summary>DFA-driven byte-level lexer. Reads from a <see cref="Stream"/> in 16 KiB chunks.</summary>
public sealed class Lexer
{
    private const int Chunk = 16384;

    private readonly Stream _stream;
    private byte[] _buf;
    private int _bufLen;
    private int _bufPos;
    private bool _eof;
    private int _offset;
    private int _line = 1;
    private int _col = 1;
    private readonly DfaConfig _dfa;
    private readonly short _eofKind;
    private readonly short _errorKind;

    public Lexer(Stream stream, DfaConfig dfa, short eofKind, short errorKind)
    {
        _stream = stream;
        _buf = new byte[Chunk * 2];
        _dfa = dfa;
        _eofKind = eofKind;
        _errorKind = errorKind;
    }

    private Pos CurPos() => new(_offset, _line, _col);

    private bool ReadMore()
    {
        if (_eof) return false;
        if (_buf.Length - _bufLen < Chunk)
        {
            int newLen = _buf.Length;
            while (newLen - _bufLen < Chunk) newLen *= 2;
            Array.Resize(ref _buf, newLen);
        }
        int n = _stream.Read(_buf, _bufLen, _buf.Length - _bufLen);
        if (n <= 0) { _eof = true; return false; }
        _bufLen += n;
        return true;
    }

    private void Ensure(int want)
    {
        while (!_eof && _bufLen - _bufPos < want)
        {
            if (!ReadMore()) break;
        }
    }

    // Fast-path: bump column directly for pure ASCII non-newline slices;
    // byte-by-byte walk otherwise so multi-byte codepoints count as one column.
    private void Advance(int n)
    {
        int end = _bufPos + n;
        bool needsWalk = false;
        for (int k = _bufPos; k < end; k++)
        {
            byte b = _buf[k];
            if (b == (byte)'\n' || b >= 0x80) { needsWalk = true; break; }
        }
        if (!needsWalk)
        {
            _col += n;
            _offset += n;
            _bufPos = end;
        }
        else
        {
            while (_bufPos < end)
            {
                byte b = _buf[_bufPos++]; _offset++;
                if (b == (byte)'\n') { _line++; _col = 1; }
                else if ((b & 0xC0) != 0x80) _col++;
            }
        }
        if (_bufPos > 65536)
        {
            Array.Copy(_buf, _bufPos, _buf, 0, _bufLen - _bufPos);
            _bufLen -= _bufPos; _bufPos = 0;
        }
    }

    private (int Len, short Kind) LongestMatch()
    {
        while (true)
        {
            uint state = _dfa.Start;
            int pos = _bufPos;
            int bestLen = 0;
            short bestKind = _errorKind;
            while (pos < _bufLen)
            {
                uint next = _dfa.Trans[(int)(state * 256) + _buf[pos]];
                if (next == 0) break;
                pos++;
                state = next;
                ushort acc = _dfa.Accept[state];
                if (acc != 0)
                {
                    bestLen = pos - _bufPos;
                    bestKind = (short)acc;
                }
            }
            if (!_eof && pos == _bufLen && bestLen > 0)
            {
                if (ReadMore()) continue;
            }
            return (bestLen, bestKind);
        }
    }

    /// <summary>Produce the next token. Returns repeated EOF once input is fully consumed.</summary>
    public Token NextToken()
    {
        Ensure(Chunk);
        if (_bufLen - _bufPos == 0) { var p = CurPos(); return new Token(_eofKind, Span.Point(p), ""); }
        var best = LongestMatch();
        var start = CurPos();
        if (best.Len == 0)
        {
            byte b = _buf[_bufPos];
            int cpLen = b < 0x80 ? 1 : b < 0xE0 ? 2 : b < 0xF0 ? 3 : 4;
            int take = Math.Min(cpLen, _bufLen - _bufPos);
            string text = Encoding.UTF8.GetString(_buf, _bufPos, take);
            Advance(take);
            return new Token(_errorKind, new Span(start, CurPos()), text);
        }
        string tokText = Encoding.UTF8.GetString(_buf, _bufPos, best.Len);
        Advance(best.Len);
        return new Token(best.Kind, new Span(start, CurPos()), tokText);
    }
}

/// <summary>Grammar-specific callbacks a generated parser wires into the runtime.</summary>
public sealed record ParserConfig(
    int K,
    short EofKind,
    Predicate<short> IsSkip,
    Action<Parser> Drive);

/// <summary>
/// Pull-based parser. Obtain one via a generated <c>ParseXxx</c> factory
/// and iterate it (or call <see cref="NextEvent"/> directly) to walk the parse.
/// </summary>
public sealed class Parser : IEnumerable<Event>, IEnumerator<Event>
{
    /// <summary>Sentinel state meaning "the parser has terminated".</summary>
    public const int Terminated = -1;

    private readonly Lexer _lex;
    private readonly Token[] _lookBuf;
    private Pos _prevEnd;
    private int _state;
    private readonly Stack<int> _ret = new();
    private readonly Queue<Event> _queue = new();
    private readonly Queue<Token> _pendingSkips = new();
    private bool _eofChecked;
    private Event? _current;
    private readonly ParserConfig _cfg;

    public Parser(Lexer lex, int entry, ParserConfig cfg)
    {
        _lex = lex;
        _cfg = cfg;
        _state = entry;
        _lookBuf = new Token[cfg.K];
        for (int i = 0; i < cfg.K; i++) _lookBuf[i] = PumpToken();
        _prevEnd = _lookBuf[0].Span.Start;
    }

    /// <summary>Peek at the i-th lookahead token.</summary>
    public Token Look(int i) => _lookBuf[i];

    /// <summary>Current state id. Read at the top of every driver iteration.</summary>
    public int State() => _state;
    public void SetState(int s) => _state = s;
    public void PushRet(int s) => _ret.Push(s);
    public int PopRet() => _ret.Count > 0 ? _ret.Pop() : Terminated;
    public bool QueueIsEmpty() => _queue.Count == 0;

    /// <summary>True iff the current lookahead matches any of the given prefixes.</summary>
    public bool MatchesFirst(short[][] set)
    {
        foreach (var seq in set)
        {
            bool match = true;
            for (int i = 0; i < seq.Length; i++)
            {
                if (_lookBuf[i].Kind != seq[i]) { match = false; break; }
            }
            if (match) return true;
        }
        return false;
    }

    public void Enter(int rule)
    {
        var pos = _lookBuf[0].Span.Start;
        _prevEnd = pos;
        Emit(new EnterEvent(rule, pos));
    }

    public void Exit(int rule) => Emit(new ExitEvent(rule, _prevEnd));

    public void Consume()
    {
        var prev = _lookBuf[0];
        _prevEnd = prev.Span.End;
        Emit(new TokenEvent(prev));
        AdvanceLook();
    }

    public void TryConsume(short kind, short[] sync, string name)
    {
        if (Look(0).Kind == kind) { Consume(); return; }
        ErrorHere($"expected {name}");
        RecoverTo(sync);
        if (Look(0).Kind == kind) Consume();
    }

    private static bool ContainsKind(short[] set, short k)
    {
        foreach (var x in set) if (x == k) return true;
        return false;
    }

    public void RecoverTo(short[] sync)
    {
        while (Look(0).Kind != _cfg.EofKind && !ContainsKind(sync, Look(0).Kind))
        {
            Emit(new TokenEvent(Look(0)));
            AdvanceLook();
        }
    }

    public void ErrorHere(string msg) => Emit(new ErrorEvent(new ParseError(msg, Look(0).Span)));

    public Event? NextEvent()
    {
        while (true)
        {
            if (_queue.Count > 0) return _queue.Dequeue();
            if (_state == Terminated)
            {
                if (!_eofChecked)
                {
                    _eofChecked = true;
                    if (Look(0).Kind != _cfg.EofKind)
                    {
                        ErrorHere("expected end of input");
                        while (Look(0).Kind != _cfg.EofKind)
                        {
                            Emit(new TokenEvent(Look(0)));
                            AdvanceLook();
                        }
                    }
                    FlushSkipsBefore(Look(0).Span.End);
                    continue;
                }
                return null;
            }
            _cfg.Drive(this);
        }
    }

    public Event Current => _current!;
    object IEnumerator.Current => Current;
    public bool MoveNext() { var ev = NextEvent(); _current = ev; return ev is not null; }
    public void Reset() => throw new NotSupportedException("Parser is single-pass.");
    public void Dispose() { }

    public IEnumerator<Event> GetEnumerator() => this;
    IEnumerator IEnumerable.GetEnumerator() => GetEnumerator();

    private Token PumpToken()
    {
        while (true)
        {
            var t = _lex.NextToken();
            if (_cfg.IsSkip(t.Kind)) { _pendingSkips.Enqueue(t); continue; }
            return t;
        }
    }

    private void AdvanceLook()
    {
        for (int i = 0; i < _cfg.K - 1; i++) _lookBuf[i] = _lookBuf[i + 1];
        _lookBuf[_cfg.K - 1] = PumpToken();
    }

    private void FlushSkipsBefore(Pos pos)
    {
        while (_pendingSkips.Count > 0 && _pendingSkips.Peek().Span.End.Offset <= pos.Offset)
        {
            _queue.Enqueue(new TokenEvent(_pendingSkips.Dequeue()));
        }
    }

    private void Emit(Event ev)
    {
        var start = ev switch
        {
            EnterEvent e => e.Pos,
            ExitEvent e => e.Pos,
            TokenEvent t => t.Token.Span.Start,
            ErrorEvent x => x.Error.Span.Start,
            _ => throw new InvalidOperationException("unknown Event subtype"),
        };
        FlushSkipsBefore(start);
        _queue.Enqueue(ev);
    }
}
